<template><div class="overlay"><section class="modal"><h3>{{t('promptops.datasets.importDataset')}}</h3><input type="file" accept="application/json,.json" @change="selectFile"><p v-if="fileName">{{fileName}} · {{fileSize}}</p><div v-if="preview" class="preview"><h4>{{t('promptops.datasets.importPreview')}}</h4><p>{{preview.document?.dataset.name||'—'}} · {{t('promptops.datasets.validCases')}}: {{preview.acceptedCaseCount}}</p><p>{{t('promptops.datasets.errors')}}: {{preview.issues.length}}</p><p class="muted">{{t('promptops.datasets.atomic')}}</p><ul><li v-for="issue in preview.issues" :key="issue.path+issue.caseIndex" class="error">#{{issue.caseIndex!==undefined?issue.caseIndex+1:'—'}} {{issue.caseName||''}} · {{issue.path}} · {{issue.message}}</li></ul></div><p v-if="error" class="error">{{error}}</p><div class="actions"><button @click="$emit('close')">{{t('promptops.datasets.close')}}</button><button class="primary" :disabled="!preview?.valid||submitting" @click="confirm">{{t('promptops.datasets.confirmImport')}}</button></div></section></div></template>
<script setup lang="ts">import{ref}from'vue';import{useI18n}from'vue-i18n';import type{DatasetImportPreview}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../../services/promptops';import{usePromptOpsUiStore}from'../../../stores/promptops/usePromptOpsUiStore';const emit=defineEmits<{close:[];imported:[string]}>();const{t}=useI18n();const services=usePromptOpsServices(),store=usePromptOpsUiStore(),preview=ref<DatasetImportPreview>(),fileName=ref(''),fileSize=ref(''),error=ref(''),submitting=ref(false);const selectFile=async(event:Event)=>{const file=(event.target as HTMLInputElement).files?.[0];if(!file)return;fileName.value=file.name;fileSize.value=`${Math.ceil(file.size/1024)} KB`;if(file.size>5_000_000){error.value=String(t('promptops.datasets.fileTooLarge'));preview.value=undefined;return}try{preview.value=services.datasetService.previewImport(await file.text());error.value=''}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}};const confirm=async()=>{if(!preview.value?.valid||submitting.value)return;submitting.value=true;try{const dataset=await services.datasetService.importAtomic(store.currentWorkspaceId,preview.value);emit('imported',dataset.id)}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{submitting.value=false}}</script>
<style scoped>.overlay{position:fixed;inset:0;background:#0008;display:grid;place-items:center;z-index:30}.modal{width:min(720px,92vw);max-height:85vh;overflow:auto;background:var(--n-color,#fff);padding:22px;border-radius:12px}.preview{margin:14px 0;padding:12px;background:#f8fafc;color:#111827;border-radius:8px}.actions{display:flex;justify-content:flex-end;gap:8px}.primary{background:#2563eb;color:#fff}.error{color:#b91c1c}.muted{color:#64748b}</style>
